158	func handleTap(_ parsed: ParsedOptions) throws -> Int32 {
159	    let target = try resolveTarget(from: parsed)
160	    let accessibilityId = parsed.options["--id"]
161	    let accessibilityLabel = parsed.options["--label"]
162	    let isDouble = parsed.flags.contains("--double")
163	    let includeAll = parsed.flags.contains("--all")
164	    if accessibilityId != nil || accessibilityLabel != nil {
165	        let preDelay = try optionalDoubleOption("--pre-delay", from: parsed) ?? 0
166	        let postDelay = try optionalDoubleOption("--post-delay", from: parsed) ?? 0
167	
168	        try ensureAccessibilityTrusted()
169	        try activateTarget(target)
170	        if preDelay > 0 {
171	            Thread.sleep(forTimeInterval: preDelay)
172	        }
173	
174	        let root = try accessibilityRootElement(for: target)
175	        let targetUdid = simulatorUdid(from: target)
176	        let simulatorContentRoot = simulatorContentRootElement(from: root, udid: targetUdid)
177	        let searchRoots: [UIElement]
178	        if case .simulator = target, !includeAll {
179	            if let contentRoot = simulatorContentRoot {
180	                let auxiliaryRoots = simulatorAuxiliaryContainerCandidates(from: root, excluding: contentRoot, udid: targetUdid).map(\.element)
181	                searchRoots = [contentRoot] + auxiliaryRoots
182	            } else {
183	                searchRoots = [root]
184	            }
185	        } else {
186	            searchRoots = [root]
187	        }
188	
189	        guard let matchedElement = findAccessibilityElement(
190	            in: searchRoots,
191	            identifier: accessibilityId,
192	            label: accessibilityLabel
193	        ) else {
194	            var selectors: [String] = []
195	            if let accessibilityId {
196	                selectors.append("id='\(accessibilityId)'")
197	            }
198	            if let accessibilityLabel {
199	                selectors.append("label='\(accessibilityLabel)'")
200	            }
201	            let selectorText = selectors.joined(separator: " and ")
202	            if case .simulator = target, !includeAll {
203	                let auxiliaryLabels = simulatorContentRoot.map {
204	                    simulatorAuxiliaryContainerLabels(from: root, excluding: $0, udid: targetUdid)
205	                } ?? []
206	                throw NativeError.commandFailed(simulatorSelectorNotFoundMessage(selectorText: selectorText, auxiliaryLabels: auxiliaryLabels))
207	            }
208	            throw NativeError.commandFailed("No accessibility element matched \(selectorText).")
209	        }
210	
211	        if isDouble {
212	            guard let frame = FrameAttribute(matchedElement) else {
213	                throw NativeError.commandFailed("Matched accessibility element has no frame for double-click.")
214	            }
215	            sendDoubleClick(at: CGPoint(x: frame.midX, y: frame.midY))
216	        } else {
217	            try performPrimaryAction(on: matchedElement)
218	        }
219	
220	        if postDelay > 0 {
221	            Thread.sleep(forTimeInterval: postDelay)
222	        }
223	        return 0
224	    }
225	
226	    let xRaw = parsed.options["-x"]
227	    let yRaw = parsed.options["-y"]
228	    guard let xRaw, let yRaw, let x = Double(xRaw), let y = Double(yRaw) else {
229	        throw NativeError.invalidArguments("tap requires -x and -y coordinates.")
230	    }
231	    let preDelay = try optionalDoubleOption("--pre-delay", from: parsed) ?? 0
232	    let postDelay = try optionalDoubleOption("--post-delay", from: parsed) ?? 0
233	    try ensureAccessibilityTrusted()
234	    try activateTarget(target)
235	    if preDelay > 0 {
236	        Thread.sleep(forTimeInterval: preDelay)
237	    }
238	    let backend = resolveInputBackend(for: target)
239	    switch backend {
240	    case .indigoHID(let client):
241	        if isDouble {
242	            _ = client.tap(x: x, y: y)
243	            Thread.sleep(forTimeInterval: 0.1)
244	            _ = client.tap(x: x, y: y)
245	        } else {
246	            _ = client.tap(x: x, y: y)
247	        }
248	    case .cgevent:
249	        let point = try pointInWindow(x: x, y: y, for: target)
250	        if isDouble {
251	            sendDoubleClick(at: point)
252	        } else {
253	            sendClick(at: point)
254	        }
255	    }
256	    if postDelay > 0 {
257	        Thread.sleep(forTimeInterval: postDelay)
258	    }
259	    return 0
260	}
