431	    let target = try resolveTarget(from: parsed)
432	    let startX = try requiredOption("--start-x", from: parsed)
433	    let startY = try requiredOption("--start-y", from: parsed)
434	    let endX = try requiredOption("--end-x", from: parsed)
435	    let endY = try requiredOption("--end-y", from: parsed)
436	    guard let startXValue = Double(startX),
437	          let startYValue = Double(startY),
438	          let endXValue = Double(endX),
439	          let endYValue = Double(endY) else {
440	        throw NativeError.invalidArguments("swipe requires numeric start/end coordinates.")
441	    }
442	    let duration = try optionalDoubleOption("--duration", from: parsed)
443	    let preDelay = try optionalDoubleOption("--pre-delay", from: parsed) ?? 0
444	    let postDelay = try optionalDoubleOption("--post-delay", from: parsed) ?? 0
445	    try ensureAccessibilityTrusted()
446	    try activateTarget(target)
447	    if preDelay > 0 {
448	        Thread.sleep(forTimeInterval: preDelay)
449	    }
450	    let backend = resolveInputBackend(for: target)
451	    switch backend {
452	    case .indigoHID(let client):
453	        _ = client.swipe(fromX: startXValue, fromY: startYValue, toX: endXValue, toY: endYValue, duration: duration)
454	    case .cgevent:
455	        let start = try pointForInput(x: startXValue, y: startYValue, for: target)
456	        let end = try pointForInput(x: endXValue, y: endYValue, for: target)
457	        sendSwipe(from: start, to: end, duration: duration)
458	    }
459	    if postDelay > 0 {
460	        Thread.sleep(forTimeInterval: postDelay)
