func handleMenuAction(_ parsed: ParsedOptions) throws -> Int32 {
    // ... ĻĖ░ņĪ┤ ņĮöļō£ ...
    let itemPath = itemName.split(separator: ">").map {
        $0.trimmingCharacters(in: .whitespaces)
