    var currentMenu = menuItem  // ņ▓½ ļ▓łņ¦Ė ļ®öļē┤ ņŚ┤ĻĖ░
    AXUIElementPerformAction(currentMenu, kAXPressAction as CFString)
    Thread.sleep(forTimeInterval: 0.2)

    for (depth, pathComponent) in itemPath.enumerated() {
        let isLast = depth == itemPath.count - 1
        let children = flattenMenuChildren(currentMenu)

        guard let found = children.first(where: {
            let title = StringAttribute($0, kAXTitleAttribute as CFString) ?? ""
            return normalizeText(title) == normalizeText(pathComponent)
        }) else {
            AXUIElementPerformAction(currentMenu, "AXCancel" as CFString)
            throw NativeError.commandFailed(
                "Menu item '\(pathComponent)' not found at depth \(depth + 1)."
