### 5-2. modifier cleanup ļ│┤ņ×ź (defer Ēī©Ēä┤)

```swift
func sendKeyCombo(modifiers: [Int], key: Int) {
    let source = CGEventSource(stateID: .hidSystemState)

    var flags: CGEventFlags = []
    for modifier in modifiers {
        if let flag = keycodeToFlag[CGKeyCode(modifier)] {
            flags.insert(flag)
        }
    }

    // modifier down
    for modifier in modifiers {
        let event = CGEvent(keyboardEventSource: source,
                           virtualKey: CGKeyCode(modifier), keyDown: true)
        event?.flags = flags
        event?.post(tap: .cghidEventTap)
    }
    usleep(30_000)

    // defer: modifier upņØĆ ņ¢┤ļ¢ż Ļ▓ĮņÜ░ņŚÉļÅä ņŗżĒ¢ē
    defer {
        usleep(30_000)
        for modifier in modifiers.reversed() {
            let event = CGEvent(keyboardEventSource: source,
                               virtualKey: CGKeyCode(modifier), keyDown: false)
            event?.post(tap: .cghidEventTap)
        }
    }

    // main key
    let keyDown = CGEvent(keyboardEventSource: source,
                         virtualKey: CGKeyCode(key), keyDown: true)
    keyDown?.flags = flags
    keyDown?.post(tap: .cghidEventTap)

    let keyUp = CGEvent(keyboardEventSource: source,
                       virtualKey: CGKeyCode(key), keyDown: false)
    keyUp?.flags = flags
    keyUp?.post(tap: .cghidEventTap)
}
```

