/**
 * Unit tests for mcp-baepsae internal functions.
 *
 * Since the functions are not exported (refactoring is tracked in issue #8),
 * these tests exercise them indirectly through the MCP client interface.
 * They focus on edge cases, error paths, and specific behaviors that the
 * existing contract tests do not cover.
 *
 * No booted simulator is required.
 */

import test from "node:test";
import assert from "node:assert/strict";
import path from "node:path";
import os from "node:os";
import { fileURLToPath } from "node:url";
import { writeFileSync, chmodSync, mkdirSync, rmSync, rmdirSync, readFileSync, mkdtempSync, readdirSync } from "node:fs";
import { execFileSync } from "node:child_process";
import { createRequire } from "node:module";

import { Client } from "@modelcontextprotocol/sdk/client/index.js";
import { StdioClientTransport } from "@modelcontextprotocol/sdk/client/stdio.js";

const __filename = fileURLToPath(import.meta.url);
const __dirname = path.dirname(__filename);
const projectRoot = path.resolve(__dirname, "..");
const require = createRequire(import.meta.url);
const { version } = require("../package.json");

// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------

function extractText(result) {
  return result.content
    .filter((item) => item.type === "text")
    .map((item) => item.text)
    .join("\n");
}

function listSwiftSources(directory) {
  const entries = readdirSync(directory, { withFileTypes: true });
  return entries
    .flatMap((entry) => {
      const fullPath = path.join(directory, entry.name);
      if (entry.isDirectory()) {
        return listSwiftSources(fullPath);
      }
      if (entry.isFile() && entry.name.endsWith(".swift") && entry.name !== "main.swift") {
        return [fullPath];
      }
      return [];
    })
    .sort();
}

